//! # Resonance Knot â€” Calibration (Phase 2 hook surface)
//!
//! Phase 1 ships only the data structures and a stub probe. Phase 2 will
//! replace [`stub_calibration_probe`] with a real attention-tap into the
//! existing inference kernel that captures per-dimension Q/K/V amplitudes
//! and phase alignment over a probe corpus.
//!
//! The data shape mirrors the Lean `AttentionQKVPattern` (Float fields)
//! and downstream `extract_value_gated` filter.

use super::format::*;
use std::collections::BTreeMap;

/// Per-dimension attention measurement captured during a forward pass.
/// Mirrors Lean `AttentionQKVPattern` (the Float fields).
#[derive(Debug, Clone)]
pub struct AttentionMeasurement {
    /// Dimension index in `[0, d)`.
    pub frequency: u32,
    pub query_amplitude: f32,
    pub key_amplitude: f32,
    pub value_amplitude: f32,
    pub query_phase_variance: f32,
    pub key_phase_variance: f32,
    pub value_phase_variance: f32,
    pub qk_phase_alignment: f32,
    pub output_amplitude: f32,
}

/// Per-layer measurement bundle. The Phase 2 calibration runner produces
/// one of these per layer per probe-corpus token.
#[derive(Debug, Clone)]
pub struct LayerMeasurement {
    pub layer_idx: u32,
    pub measurements: Vec<AttentionMeasurement>,
}

/// Reduce per-token measurements into per-layer aggregates (mean
/// amplitudes, mean phase alignment).
///
/// Group by `layer_idx`, then for each group compute the per-dimension
/// mean across all measurements at that dimension. Phase 2 calibration
/// code pipes its raw output through this before manifest extraction.
pub fn aggregate_measurements(per_token: &[LayerMeasurement]) -> Vec<LayerMeasurement> {
    // Group all measurements by (layer_idx, frequency), preserving
    // ascending order on both keys via BTreeMap.
    let mut by_layer: BTreeMap<u32, BTreeMap<u32, Vec<AttentionMeasurement>>> = BTreeMap::new();
    for layer in per_token {
        let layer_entry = by_layer.entry(layer.layer_idx).or_default();
        for m in &layer.measurements {
            layer_entry.entry(m.frequency).or_default().push(m.clone());
        }
    }

    let mut out = Vec::with_capacity(by_layer.len());
    for (layer_idx, dims) in by_layer {
        let mut measurements = Vec::with_capacity(dims.len());
        for (freq, ms) in dims {
            let n = ms.len() as f32;
            let inv_n = if n > 0.0 { 1.0 / n } else { 0.0 };
            let mut acc = AttentionMeasurement {
                frequency: freq,
                query_amplitude: 0.0,
                key_amplitude: 0.0,
                value_amplitude: 0.0,
                query_phase_variance: 0.0,
                key_phase_variance: 0.0,
                value_phase_variance: 0.0,
                qk_phase_alignment: 0.0,
                output_amplitude: 0.0,
            };
            for m in &ms {
                acc.query_amplitude += m.query_amplitude;
                acc.key_amplitude += m.key_amplitude;
                acc.value_amplitude += m.value_amplitude;
                acc.query_phase_variance += m.query_phase_variance;
                acc.key_phase_variance += m.key_phase_variance;
                acc.value_phase_variance += m.value_phase_variance;
                acc.qk_phase_alignment += m.qk_phase_alignment;
                acc.output_amplitude += m.output_amplitude;
            }
            acc.query_amplitude *= inv_n;
            acc.key_amplitude *= inv_n;
            acc.value_amplitude *= inv_n;
            acc.query_phase_variance *= inv_n;
            acc.key_phase_variance *= inv_n;
            acc.value_phase_variance *= inv_n;
            acc.qk_phase_alignment *= inv_n;
            acc.output_amplitude *= inv_n;
            measurements.push(acc);
        }
        out.push(LayerMeasurement {
            layer_idx,
            measurements,
        });
    }
    out
}

/// Apply `value_standing_and_gated`-style filtering to produce a
/// [`SpectralManifest`] from one layer's aggregated measurements.
///
/// Mirrors Lean `extract_value_gated`: a dimension is "standing" iff
/// **all** of `query_amplitude`, `key_amplitude`, `value_amplitude`, and
/// `qk_phase_alignment` exceed `threshold`. The resulting manifest uses
/// `value_amplitude` for [`SpectralManifest::amplitudes`] and
/// `qk_phase_alignment` for [`SpectralManifest::phase_alignment`].
pub fn manifest_from_measurements(
    layer: &LayerMeasurement,
    d: u32,
    threshold: f32,
) -> SpectralManifest {
    // Filter then collect in order. The aggregator emits measurements
    // in ascending-frequency order (BTreeMap), so the resulting indices
    // satisfy the SpectralManifest sorted-ascending invariant.
    let mut standing_indices: Vec<u32> = Vec::new();
    let mut amplitudes: Vec<f32> = Vec::new();
    let mut phase_alignment: Vec<f32> = Vec::new();

    for m in &layer.measurements {
        if m.frequency >= d {
            continue;
        }
        if m.query_amplitude > threshold
            && m.key_amplitude > threshold
            && m.value_amplitude > threshold
            && m.qk_phase_alignment > threshold
        {
            standing_indices.push(m.frequency);
            amplitudes.push(m.value_amplitude);
            phase_alignment.push(m.qk_phase_alignment);
        }
    }

    let k = standing_indices.len() as u32;
    SpectralManifest {
        d,
        k,
        standing_indices,
        amplitudes,
        phase_alignment,
    }
}

/// STUB Phase 2 hook: synthesize a measurement by sampling the dimension
/// space uniformly. Returns `num_layers` [`LayerMeasurement`]s, each with
/// `d` measurements where `query_amplitude = key_amplitude =
/// value_amplitude = 0.5`, all phase variances = `0.05`, and
/// `qk_phase_alignment = 0.7`. Each measurement's `frequency` is its
/// index in `[0, d)`. Replaced in Phase 2 by a real attention tap into
/// the existing kernel.
pub fn stub_calibration_probe(d: u32, num_layers: u32) -> Vec<LayerMeasurement> {
    (0..num_layers)
        .map(|layer_idx| {
            let measurements = (0..d)
                .map(|freq| AttentionMeasurement {
                    frequency: freq,
                    query_amplitude: 0.5,
                    key_amplitude: 0.5,
                    value_amplitude: 0.5,
                    query_phase_variance: 0.05,
                    key_phase_variance: 0.05,
                    value_phase_variance: 0.05,
                    qk_phase_alignment: 0.7,
                    output_amplitude: 0.5,
                })
                .collect();
            LayerMeasurement {
                layer_idx,
                measurements,
            }
        })
        .collect()
}

/// Attention probe interface â€” anything that can produce per-layer
/// [`AttentionMeasurement`] vectors from a probe corpus. Phase 3 ships
/// [`FakeAttentionProbe`]; Phase 4 swaps in [`RealKernelProbe`].
///
/// The trait surface lets `encode-rknot` accept
/// `--calibration-probe <fake|real>` in Phase 4 without rewiring.
pub trait AttentionProbe {
    fn probe(&mut self, corpus: &[u32]) -> Result<Vec<LayerMeasurement>, String>;
}

/// Phase 3 stub: returns deterministic measurements derived from the
/// corpus token IDs. Not a real attention probe â€” the surface exists so
/// `encode-rknot` can have a `--calibration-probe <fake|real>` flag in
/// Phase 4 without rewiring.
///
/// The synthesized measurements are stable across runs given the same
/// `corpus`: every per-(layer, dim) field is a pure function of
/// `(layer_idx, freq, corpus)`.
pub struct FakeAttentionProbe {
    pub d: u32,
    pub num_layers: u32,
}

impl AttentionProbe for FakeAttentionProbe {
    fn probe(&mut self, corpus: &[u32]) -> Result<Vec<LayerMeasurement>, String> {
        // Fold the corpus into a deterministic 32-bit seed via a small
        // FNV-1a-style mix. No external crates; pure stdlib arithmetic.
        let mut corpus_hash: u32 = 0x811c_9dc5;
        for tok in corpus {
            corpus_hash ^= *tok;
            corpus_hash = corpus_hash.wrapping_mul(0x0100_0193);
        }

        let out = (0..self.num_layers)
            .map(|layer_idx| {
                let measurements = (0..self.d)
                    .map(|freq| {
                        // Deterministic per-(layer, dim, corpus) salt.
                        let mut h = corpus_hash;
                        h ^= layer_idx.wrapping_mul(0x9E37_79B1);
                        h = h.wrapping_mul(0x0100_0193);
                        h ^= freq.wrapping_mul(0x85EB_CA77);
                        h = h.wrapping_mul(0x0100_0193);
                        // Map each derived hash into [0, 1) by taking the
                        // top 24 bits (avoid f32 mantissa rounding bias).
                        let unit = |x: u32| -> f32 { ((x >> 8) as f32) / ((1u32 << 24) as f32) };
                        let q = unit(h);
                        let k = unit(h.wrapping_mul(0xC2B2_AE35));
                        let v = unit(h.wrapping_mul(0x27D4_EB2F));
                        let qpv = unit(h.wrapping_mul(0x1656_67B1)) * 0.1;
                        let kpv = unit(h.wrapping_mul(0x9E37_79B9)) * 0.1;
                        let vpv = unit(h.wrapping_mul(0x6C07_8965)) * 0.1;
                        let qk = unit(h.wrapping_mul(0xCC9E_2D51));
                        let out_amp = unit(h.wrapping_mul(0x1B87_3593));
                        AttentionMeasurement {
                            frequency: freq,
                            query_amplitude: q,
                            key_amplitude: k,
                            value_amplitude: v,
                            query_phase_variance: qpv,
                            key_phase_variance: kpv,
                            value_phase_variance: vpv,
                            qk_phase_alignment: qk,
                            output_amplitude: out_amp,
                        }
                    })
                    .collect();
                LayerMeasurement {
                    layer_idx,
                    measurements,
                }
            })
            .collect();
        Ok(out)
    }
}

/// Phase 4 placeholder: returns a "not implemented" error. Module 6's
/// integration will swap this in once the `model.rs` forward-pass tap
/// lands.
pub struct RealKernelProbe<'a> {
    pub model_path: &'a std::path::Path,
}

impl AttentionProbe for RealKernelProbe<'_> {
    fn probe(&mut self, _corpus: &[u32]) -> Result<Vec<LayerMeasurement>, String> {
        Err("RealKernelProbe lands in Phase 4 â€” wire model.rs forward-pass tap first".to_string())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn manifest_from_measurements_well_formed() {
        let probe = stub_calibration_probe(64, 1);
        // threshold below stub amplitudes (0.5) â€” but stub amps are
        // exactly 0.5, so we need a threshold strictly less than 0.5
        // for the strict-greater filter to retain them.
        let m = manifest_from_measurements(&probe[0], 64, 0.4);
        assert!(m.is_well_formed());
        assert_eq!(m.d, 64);
        assert_eq!(m.k, 64);
    }

    #[test]
    fn aggregate_preserves_dim_count() {
        // Two tokens for the same layer, same dimension count.
        let probe_a = stub_calibration_probe(32, 2);
        let probe_b = stub_calibration_probe(32, 2);
        let mut merged = probe_a;
        merged.extend(probe_b);
        let aggregated = aggregate_measurements(&merged);
        // Two distinct layer indices â‡’ two output layers.
        assert_eq!(aggregated.len(), 2);
        for layer in &aggregated {
            assert_eq!(layer.measurements.len(), 32);
        }
    }

    #[test]
    fn stub_probe_produces_expected_layer_count() {
        let probe = stub_calibration_probe(16, 8);
        assert_eq!(probe.len(), 8);
        for (i, layer) in probe.iter().enumerate() {
            assert_eq!(layer.layer_idx, i as u32);
            assert_eq!(layer.measurements.len(), 16);
            for (j, m) in layer.measurements.iter().enumerate() {
                assert_eq!(m.frequency, j as u32);
                assert_eq!(m.query_amplitude, 0.5);
                assert_eq!(m.key_amplitude, 0.5);
                assert_eq!(m.value_amplitude, 0.5);
                assert_eq!(m.qk_phase_alignment, 0.7);
                assert_eq!(m.query_phase_variance, 0.05);
                assert_eq!(m.key_phase_variance, 0.05);
                assert_eq!(m.value_phase_variance, 0.05);
            }
        }
    }

    #[test]
    fn manifest_from_measurements_threshold_zero_keeps_all() {
        let probe = stub_calibration_probe(48, 1);
        let m = manifest_from_measurements(&probe[0], 48, 0.0);
        assert!(m.is_well_formed());
        assert_eq!(m.k, 48);
        // All stub dims have value_amplitude = 0.5.
        for amp in &m.amplitudes {
            assert_eq!(*amp, 0.5);
        }
        // All stub dims have qk_phase_alignment = 0.7.
        for ph in &m.phase_alignment {
            assert_eq!(*ph, 0.7);
        }
    }

    #[test]
    fn manifest_from_measurements_threshold_max_keeps_none() {
        let probe = stub_calibration_probe(48, 1);
        // threshold above the stub's max amplitude (0.7) â€” nothing
        // survives the strict-greater filter.
        let m = manifest_from_measurements(&probe[0], 48, 1.0);
        assert!(m.is_well_formed());
        assert_eq!(m.k, 0);
        assert!(m.standing_indices.is_empty());
        assert!(m.amplitudes.is_empty());
        assert!(m.phase_alignment.is_empty());
    }

    #[test]
    fn fake_probe_produces_deterministic_measurements() {
        let corpus: Vec<u32> = vec![1, 2, 3, 5, 8, 13, 21, 34];
        let mut probe_a = FakeAttentionProbe {
            d: 16,
            num_layers: 4,
        };
        let mut probe_b = FakeAttentionProbe {
            d: 16,
            num_layers: 4,
        };
        let a = probe_a.probe(&corpus).expect("probe a ok");
        let b = probe_b.probe(&corpus).expect("probe b ok");
        assert_eq!(a.len(), b.len());
        for (la, lb) in a.iter().zip(b.iter()) {
            assert_eq!(la.layer_idx, lb.layer_idx);
            assert_eq!(la.measurements.len(), lb.measurements.len());
            for (ma, mb) in la.measurements.iter().zip(lb.measurements.iter()) {
                assert_eq!(ma.frequency, mb.frequency);
                assert_eq!(ma.query_amplitude.to_bits(), mb.query_amplitude.to_bits());
                assert_eq!(ma.key_amplitude.to_bits(), mb.key_amplitude.to_bits());
                assert_eq!(ma.value_amplitude.to_bits(), mb.value_amplitude.to_bits());
                assert_eq!(
                    ma.qk_phase_alignment.to_bits(),
                    mb.qk_phase_alignment.to_bits()
                );
                assert_eq!(
                    ma.query_phase_variance.to_bits(),
                    mb.query_phase_variance.to_bits()
                );
                assert_eq!(
                    ma.key_phase_variance.to_bits(),
                    mb.key_phase_variance.to_bits()
                );
                assert_eq!(
                    ma.value_phase_variance.to_bits(),
                    mb.value_phase_variance.to_bits()
                );
                assert_eq!(ma.output_amplitude.to_bits(), mb.output_amplitude.to_bits());
            }
        }

        // Distinct corpora should yield distinct measurements (otherwise
        // the probe is not actually deriving from the corpus).
        let mut probe_c = FakeAttentionProbe {
            d: 16,
            num_layers: 4,
        };
        let c = probe_c.probe(&[99, 100, 101]).expect("probe c ok");
        let any_diff = a.iter().zip(c.iter()).any(|(la, lc)| {
            la.measurements
                .iter()
                .zip(lc.measurements.iter())
                .any(|(ma, mc)| ma.value_amplitude.to_bits() != mc.value_amplitude.to_bits())
        });
        assert!(
            any_diff,
            "fake probe must derive measurements from corpus tokens"
        );
    }

    #[test]
    fn fake_probe_layer_count_matches_config() {
        let mut probe = FakeAttentionProbe {
            d: 32,
            num_layers: 7,
        };
        let out = probe.probe(&[42, 43, 44]).expect("probe ok");
        assert_eq!(out.len(), 7);
        for (i, layer) in out.iter().enumerate() {
            assert_eq!(layer.layer_idx, i as u32);
            assert_eq!(layer.measurements.len(), 32);
            for (j, m) in layer.measurements.iter().enumerate() {
                assert_eq!(m.frequency, j as u32);
            }
        }
    }

    #[test]
    fn real_probe_returns_phase_4_error() {
        let path = std::path::Path::new("/tmp/nonexistent.knot");
        let mut probe = RealKernelProbe { model_path: path };
        let err = probe.probe(&[1, 2, 3]).expect_err("must error in Phase 3");
        assert!(
            err.contains("Phase 4"),
            "error must mention Phase 4, got: {err}"
        );
    }
}
